-- =============================================================================
-- SimpleWMS — マルチテナント ダミーデータ（スキーマ修正＋全データ再投入版）
-- =============================================================================
-- ◆ 構成
--   テナントA: 田中食品株式会社 (T-001)
--     倉庫A-1: 東京第一倉庫  (WH-T1-01)
--     倉庫A-2: 大阪第一倉庫  (WH-T1-02)
--   テナントB: 鈴木商事株式会社 (T-002)
--     倉庫B-1: 横浜第一倉庫  (WH-T2-01)
--     倉庫B-2: 名古屋第一倉庫 (WH-T2-02)
-- =============================================================================
-- ◆ このスクリプトが行うこと
--   Step 1. UNIQUE 制約をテナント/倉庫スコープに変更（グローバル→ローカル）
--   Step 2. 既存データを全クリア
--   Step 3. ダミーデータを投入
-- =============================================================================


-- =============================================================================
-- Step 1. UNIQUE 制約をテナント・倉庫スコープに変更
-- =============================================================================
-- マルチテナントでは「同テナント内で一意」が正しい設計です。
-- グローバル UNIQUE を削除し、テナント/倉庫スコープの複合 UNIQUE に張り替えます。

-- ── suppliers ─────────────────────────────────────────────────
ALTER TABLE suppliers
  DROP CONSTRAINT IF EXISTS suppliers_supplier_code_key;
ALTER TABLE suppliers
  DROP CONSTRAINT IF EXISTS suppliers_tenant_code_key;
ALTER TABLE suppliers
  ADD CONSTRAINT suppliers_tenant_code_key
    UNIQUE (tenant_id, supplier_code);

-- ── customers ─────────────────────────────────────────────────
ALTER TABLE customers
  DROP CONSTRAINT IF EXISTS customers_customer_code_key;
ALTER TABLE customers
  DROP CONSTRAINT IF EXISTS customers_tenant_code_key;
ALTER TABLE customers
  ADD CONSTRAINT customers_tenant_code_key
    UNIQUE (tenant_id, customer_code);

-- ── products ──────────────────────────────────────────────────
ALTER TABLE products
  DROP CONSTRAINT IF EXISTS products_product_code_key;
ALTER TABLE products
  DROP CONSTRAINT IF EXISTS products_tenant_code_key;
ALTER TABLE products
  ADD CONSTRAINT products_tenant_code_key
    UNIQUE (tenant_id, product_code);

-- ── locations ─────────────────────────────────────────────────
ALTER TABLE locations
  DROP CONSTRAINT IF EXISTS locations_location_code_key;
ALTER TABLE locations
  DROP CONSTRAINT IF EXISTS locations_warehouse_code_key;
ALTER TABLE locations
  ADD CONSTRAINT locations_warehouse_code_key
    UNIQUE (warehouse_id, location_code);

-- ── arrival_headers ───────────────────────────────────────────
ALTER TABLE arrival_headers
  DROP CONSTRAINT IF EXISTS arrival_headers_arrival_no_key;
ALTER TABLE arrival_headers
  DROP CONSTRAINT IF EXISTS arrival_headers_tenant_no_key;
ALTER TABLE arrival_headers
  ADD CONSTRAINT arrival_headers_tenant_no_key
    UNIQUE (tenant_id, arrival_no);

-- ── shipping_headers ──────────────────────────────────────────
ALTER TABLE shipping_headers
  DROP CONSTRAINT IF EXISTS shipping_headers_shipping_no_key;
ALTER TABLE shipping_headers
  DROP CONSTRAINT IF EXISTS shipping_headers_tenant_no_key;
ALTER TABLE shipping_headers
  ADD CONSTRAINT shipping_headers_tenant_no_key
    UNIQUE (tenant_id, shipping_no);


-- =============================================================================
-- Step 2. 既存データを全クリア（依存関係の逆順）
-- =============================================================================

TRUNCATE TABLE
  shipping_allocations,
  shipping_lines,
  shipping_headers,
  arrival_lines,
  arrival_headers,
  inventory,
  locations,
  products,
  customers,
  suppliers,
  warehouses,
  tenants
RESTART IDENTITY CASCADE;


-- =============================================================================
-- Step 3. ダミーデータ投入
-- =============================================================================

